      ['combo-10', 'Hot Streak', 'Get a 10-orb combo', 10],
      ['combo-25', 'On Fire', 'Get a 25-orb combo', 25],
      ['combo-50', 'Unstoppable', 'Get a 50-orb combo', 50],
      ['survivor-60', 'Minute Man', 'Survive for 60 seconds', 60],
