  private loadHighScores() {
    try {
      const data = localStorage.getItem('neon-sprint-scores');
      if (data) this.highScores = JSON.parse(data);
    } catch { /* ignore */ }
  }

  private saveHighScores() {
    try {
      localStorage.setItem('neon-sprint-scores', JSON.stringify(this.highScores));
    } catch { /* ignore */ }
  }

  private loadAchievements() {
    try {
      const data = localStorage.getItem('neon-sprint-achievements');
      if (data) {
        const saved = JSON.parse(data) as Record<string, boolean>;
        for (const a of this.achievements) {
          if (saved[a.id]) a.unlocked = true;
        }
      }
    } catch { /* ignore */ }
  }

  private saveAchievements() {
    try {
      const map: Record<string, boolean> = {};
      for (const a of this.achievements) {
        if (a.unlocked) map[a.id] = true;
      }
      localStorage.setItem('neon-sprint-achievements', JSON.stringify(map));
    } catch { /* ignore */ }
  }

  private unlockAchievement(id: string) {
    const a = this.achievements.find(x => x.id === id);
    if (a && !a.unlocked) {
      a.unlocked = true;
      this.saveAchievements();
      this.uiSystem?.showAchievementToast(a.name);
    }
  }

  private checkAchievements() {
    // Distance achievements
    const distChecks: [string, number][] = [
      ['distance-100', 100], ['distance-500', 500], ['distance-1000', 1000],
      ['distance-2500', 2500], ['distance-5000', 5000], ['distance-10000', 10000],
    ];
    for (const [id, target] of distChecks) {
      if (this.distance >= target) this.unlockAchievement(id);
    }

    // Score achievements
    const scoreChecks: [string, number][] = [
      ['score-1000', 1000], ['score-5000', 5000], ['score-10000', 10000],
      ['score-50000', 50000], ['score-100000', 100000],
    ];
    for (const [id, target] of scoreChecks) {
      if (this.score >= target) this.unlockAchievement(id);
    }

    // Orb achievements
    const orbChecks: [string, number][] = [
      ['orbs-10', 10], ['orbs-50', 50], ['orbs-100', 100], ['orbs-250', 250],
    ];
    for (const [id, target] of orbChecks) {
      if (this.totalOrbsThisRun >= target) this.unlockAchievement(id);
    }

    // Multiplier achievements
    const multChecks: [string, number][] = [
      ['multiplier-3', 3], ['multiplier-5', 5], ['multiplier-8', 8], ['multiplier-10', 10],
    ];
    for (const [id, target] of multChecks) {
      if (this.multiplier >= target) this.unlockAchievement(id);
    }

    // Speed achievements
    const speedChecks: [string, number][] = [
      ['speed-20', 20], ['speed-30', 30], ['speed-40', 40],
    ];
    for (const [id, target] of speedChecks) {
      if (this.speed >= target) this.unlockAchievement(id);
    }
    if (this.speed >= MAX_SPEED) this.unlockAchievement('speed-king');

    // Combo achievements
    const comboChecks: [string, number][] = [
      ['combo-10', 10], ['combo-25', 25], ['combo-50', 50],
    ];
    for (const [id, target] of comboChecks) {
      if (this.currentCombo >= target) this.unlockAchievement(id);
    }

    // Survival achievements
    const survChecks: [string, number][] = [
      ['survivor-60', 60], ['survivor-180', 180], ['survivor-300', 300],
    ];
    for (const [id, target] of survChecks) {
      if (this.elapsedTime >= target) this.unlockAchievement(id);
    }
  }

  private createPlayerVisual() {
    const mat = new MeshStandardMaterial({
      color: 0x003366,
      emissive: new Color(0x00ffff),
      emissiveIntensity: 2,
      transparent: true,
      opacity: 0.7,
    });
    const geo = new IcosahedronGeometry(0.25, 1);
    this.playerMesh = new Mesh(geo, mat);
    this.playerMesh.position.set(0, 0.5, -1.5);
    this.scene.add(this.playerMesh);

    const glowMat = new MeshBasicMaterial({
      color: 0x00ffff,
      transparent: true,
      opacity: 0.2,
      blending: AdditiveBlending,
    });
    this.playerGlow = new Mesh(new SphereGeometry(0.4, 16, 16), glowMat);
    this.playerGlow.position.copy(this.playerMesh.position);
    this.scene.add(this.playerGlow);
  }

  private hidePlayerVisual() {
    this.playerMesh.visible = false;
    this.playerGlow.visible = false;
  }

  private showPlayerVisual() {
    this.playerMesh.visible = true;
    this.playerGlow.visible = true;
  }

  private createSpeedLines() {
    const mat = new MeshBasicMaterial({
      color: 0x00aaff,
      transparent: true,
      opacity: 0,
      blending: AdditiveBlending,
    });
    for (let i = 0; i < 20; i++) {
      const geo = new BoxGeometry(0.02, 0.02, 2 + Math.random() * 3);
      const line = new Mesh(geo, mat.clone());
      line.position.set(
        (Math.random() - 0.5) * 6,
        Math.random() * 3 + 0.5,
        (Math.random() - 0.5) * 40 - 20,
      );
      line.visible = false;
      this.scene.add(line);
      this.speedLines.push(line);
    }
  }

  private updateSpeedLines(delta: number) {
    const speedFraction = (this.speed - BASE_SPEED) / (MAX_SPEED - BASE_SPEED);
    const opacity = Math.max(0, speedFraction - 0.3) * 0.5;
    const show = opacity > 0.01;

    for (const line of this.speedLines) {
      line.visible = show;
      if (show) {
        (line.material as MeshBasicMaterial).opacity = opacity;
        line.position.z += this.speed * delta;
        if (line.position.z > DESPAWN_Z) {
          line.position.z = SPAWN_Z + Math.random() * 20;
          line.position.x = (Math.random() - 0.5) * 6;
          line.position.y = Math.random() * 3 + 0.5;
        }
      }
    }
  }

  private createObstaclePool() {
    for (let i = 0; i < 30; i++) {
      const colorIdx = i % OBSTACLE_COLORS.length;
      const factoryIdx = i % OBSTACLE_FACTORIES.length;
      const group = OBSTACLE_FACTORIES[factoryIdx](OBSTACLE_COLORS[colorIdx]);
      group.visible = false;
      this.scene.add(group);
      this.obstacles.push({ group, lane: 1, active: false, width: 1.6 });
    }
  }

  private createCollectiblePool() {
    for (let i = 0; i < 40; i++) {
      const colorIdx = i % COLLECTIBLE_COLORS.length;
      const mat = createCollectibleMaterial(COLLECTIBLE_COLORS[colorIdx]);
      const mesh = new Mesh(new SphereGeometry(0.2, 12, 12), mat);
      mesh.visible = false;
      this.scene.add(mesh);
      this.collectibles.push({
        mesh, lane: 1, active: false, pulsePhase: Math.random() * Math.PI * 2,
        value: ORB_BASE_SCORE,
      });
    }
  }

  private spawnObstacle() {
    if (!this.modeConfig.hasObstacles) return;

    const free = this.obstacles.find(o => !o.active);
    if (!free) return;

    // Pick a lane (or two)
    const lane = Math.floor(Math.random() * 3);
    free.lane = lane;
    free.active = true;
    free.group.visible = true;
    free.group.position.set(LANE_POSITIONS[lane], 0, SPAWN_Z);
    free.group.rotation.y = Math.random() * Math.PI * 2;

    // Sometimes spawn a second obstacle in adjacent lane for harder difficulty
    if (this.speed > 20 && Math.random() < 0.3) {
      const free2 = this.obstacles.find(o => !o.active);
      if (free2) {
        const otherLanes = [0, 1, 2].filter(l => l !== lane);
        const lane2 = otherLanes[Math.floor(Math.random() * otherLanes.length)];
        free2.lane = lane2;
        free2.active = true;
        free2.group.visible = true;
        free2.group.position.set(LANE_POSITIONS[lane2], 0, SPAWN_Z);
        free2.group.rotation.y = Math.random() * Math.PI * 2;
      }
    }
  }

  private spawnCollectible() {
    const free = this.collectibles.find(c => !c.active);
    if (!free) return;

    const lane = Math.floor(Math.random() * 3);
    free.lane = lane;
    free.active = true;
    free.mesh.visible = true;
    free.mesh.position.set(LANE_POSITIONS[lane], 1, SPAWN_Z);
    free.value = ORB_BASE_SCORE * (1 + Math.floor(this.distance / 500));
  }

  private deactivateObstacle(o: ObstacleObj) {
    o.active = false;
    o.group.visible = false;
    o.group.position.z = SPAWN_Z - 100;
  }

  private deactivateCollectible(c: CollectibleObj) {
    c.active = false;
    c.mesh.visible = false;
    c.mesh.position.z = SPAWN_Z - 100;
  }

  // ── Public API for UI System ──────────────────────────────

  startGame(mode: GameMode = GameMode.CLASSIC) {
    this.mode = mode;
    this.modeConfig = GAME_MODES[mode];
    this.state = GameState.COUNTDOWN;
    this.countdownValue = 3;
    this.countdownTimer = 0;

    // Reset game state
    this.score = 0;
    this.distance = 0;
    this.speed = BASE_SPEED * this.modeConfig.speedMultiplier;
    this.lives = this.modeConfig.lives;
    this.multiplier = 1;
    this.multiplierTimer = 0;
    this.orbsCollected = 0;
    this.totalOrbsThisRun = 0;
    this.invincibilityTimer = 0;
    this.elapsedTime = 0;
    this.maxSpeed = this.speed;
    this.playerLane = 1;
    this.playerX = 0;
    this.targetX = 0;
    this.laneSwitchCooldown = 0;
    this.obstacleSpawnTimer = 0;
    this.collectibleSpawnTimer = 0;
    this.isNewRecord = false;
    this.longestCombo = 0;
    this.currentCombo = 0;
    this.challengeWave = 0;
    this.challengeTimer = 0;

    // Clear all active objects
    for (const o of this.obstacles) this.deactivateObstacle(o);
    for (const c of this.collectibles) this.deactivateCollectible(c);

    // Show player
    this.showPlayerVisual();
    this.playerMesh.position.x = 0;
    this.playerGlow.position.x = 0;

    // Mode-specific achievements
    const modeAchMap: Record<string, string> = {
      classic: 'mode-classic', sprint: 'mode-sprint', time_attack: 'mode-time',
      zen: 'mode-zen', endless: 'mode-endless', challenge: 'mode-challenge',
    };
    if (modeAchMap[mode]) this.unlockAchievement(modeAchMap[mode]);
  }

  pauseGame() {
    if (this.state === GameState.PLAYING) {
      this.state = GameState.PAUSED;
    }
  }

  resumeGame() {
    if (this.state === GameState.PAUSED) {
      this.state = GameState.PLAYING;
    }
  }

  quitToMenu() {
    this.state = GameState.MENU;
    this.hidePlayerVisual();
    for (const o of this.obstacles) this.deactivateObstacle(o);
    for (const c of this.collectibles) this.deactivateCollectible(c);
    for (const line of this.speedLines) line.visible = false;
  }

  showModeSelect() { this.state = GameState.MODE_SELECT; }
  showSettings() { this.state = GameState.SETTINGS; }
  showAchievements() { this.state = GameState.ACHIEVEMENTS; }
  showTutorial() { this.state = GameState.TUTORIAL; }
  showMenu() { this.state = GameState.MENU; }

  getAchievementCount(): number {
    return this.achievements.filter(a => a.unlocked).length;
  }

  // ── Main Update Loop ─────────────────────────────────────

  update(delta: number, time: number) {
    // Clamp large deltas
    const dt = Math.min(delta, 0.1);

    switch (this.state) {
      case GameState.COUNTDOWN:
        this.updateCountdown(dt);
        break;
      case GameState.PLAYING:
        this.updatePlaying(dt, time);
        break;
      case GameState.PAUSED:
        // Just animate player glow
        this.animatePlayerGlow(time);
        break;
      default:
        break;
    }
  }

  private updateCountdown(dt: number) {
    this.countdownTimer += dt;
    if (this.countdownTimer >= 1) {
      this.countdownTimer -= 1;
      this.countdownValue--;
      if (this.countdownValue <= 0) {
        this.state = GameState.PLAYING;
      }
    }
  }

  private updatePlaying(dt: number, time: number) {
    this.elapsedTime += dt;

    // Speed increase
    this.speed = Math.min(
      MAX_SPEED,
      (BASE_SPEED * this.modeConfig.speedMultiplier) + this.elapsedTime * SPEED_INCREASE_RATE,
    );
    this.maxSpeed = Math.max(this.maxSpeed, this.speed);

    // Distance
    this.distance += this.speed * dt;
    this.score += this.speed * dt * DISTANCE_SCORE_RATE * 0.1;

    // Multiplier decay
    this.multiplierTimer += dt;
    if (this.multiplierTimer > MULTIPLIER_DECAY_TIME && this.multiplier > 1) {
      this.multiplier = Math.max(1, this.multiplier - 1);
      this.multiplierTimer = 0;
      this.currentCombo = 0;
    }

    // Invincibility
    if (this.invincibilityTimer > 0) {
      this.invincibilityTimer -= dt;
      // Flash player
      this.playerMesh.visible = Math.sin(time * 20) > 0;
    }

    // Cooldowns
    if (this.laneSwitchCooldown > 0) this.laneSwitchCooldown -= dt;

    // Input
    this.handleInput();

    // Player position lerp
    this.targetX = LANE_POSITIONS[this.playerLane];
    this.playerX += (this.targetX - this.playerX) * LANE_SWITCH_SPEED * dt;
    this.playerMesh.position.x = this.playerX;
    this.playerGlow.position.x = this.playerX;

    // Player rotation (lean into turns)
    const leanAngle = (this.targetX - this.playerX) * 0.3;
    this.playerMesh.rotation.z = leanAngle;
    this.playerMesh.rotation.y += dt * 2;

    // Animate player glow
    this.animatePlayerGlow(time);

    // Move and spawn objects
    this.updateObstacles(dt);
    this.updateCollectibles(dt, time);

    // Spawn timers
    const speedFraction = this.speed / MAX_SPEED;
    const obstacleInterval = OBSTACLE_BASE_INTERVAL - speedFraction * (OBSTACLE_BASE_INTERVAL - OBSTACLE_MIN_INTERVAL);

    this.obstacleSpawnTimer += dt;
    if (this.obstacleSpawnTimer >= obstacleInterval) {
      this.obstacleSpawnTimer = 0;
      this.spawnObstacle();
    }

    this.collectibleSpawnTimer += dt;
    if (this.collectibleSpawnTimer >= COLLECTIBLE_INTERVAL) {
      this.collectibleSpawnTimer = 0;
      this.spawnCollectible();
    }

    // Speed lines
    this.updateSpeedLines(dt);

    // Check achievements
    this.checkAchievements();

    // Time limit check
    if (this.modeConfig.timeLimit > 0 && this.elapsedTime >= this.modeConfig.timeLimit) {
      this.endGame();
      return;
    }

    // Sprint target check
    if (this.modeConfig.targetDistance > 0 && this.distance >= this.modeConfig.targetDistance) {
      this.unlockAchievement('perfect-sprint');
      this.endGame();
      return;
    }

    // First run achievement
    this.unlockAchievement('first-run');
  }

  private animatePlayerGlow(time: number) {
    const scale = 1 + Math.sin(time * 3) * 0.15;
    this.playerGlow.scale.setScalar(scale);
    const glowMat = this.playerGlow.material as MeshBasicMaterial;
    glowMat.opacity = 0.15 + Math.sin(time * 4) * 0.08;
  }

  private handleInput() {
    if (this.laneSwitchCooldown > 0) return;

    let moveLeft = false;
    let moveRight = false;

    // Keyboard
    if (this._kb().getKeyDown('KeyA') || this._kb().getKeyDown('ArrowLeft')) {
      moveLeft = true;
    }
    if (this._kb().getKeyDown('KeyD') || this._kb().getKeyDown('ArrowRight')) {
      moveRight = true;
    }

    // Pause
    if (this._kb().getKeyDown('Escape') || this._kb().getKeyDown('KeyP')) {
      this.pauseGame();
      return;
    }

    // XR controller
    const left = this.input.gamepads.left;
    const right = this.input.gamepads.right;

    if (left) {
      const stick = left.getAxesValues(InputComponent.Thumbstick);
      if (stick && Math.abs(stick.x) > 0.5) {
        if (stick.x < -0.5) moveLeft = true;
        if (stick.x > 0.5) moveRight = true;
      }
    }
    if (right) {
      const stick = right.getAxesValues(InputComponent.Thumbstick);
      if (stick && Math.abs(stick.x) > 0.5) {
        if (stick.x < -0.5) moveLeft = true;
        if (stick.x > 0.5) moveRight = true;
      }
      // Pause with B button
      if (right.getButtonDown(InputComponent.B_Button)) {
        this.pauseGame();
        return;
      }
    }

    if (moveLeft && this.playerLane > 0) {
      this.playerLane--;
      this.laneSwitchCooldown = LANE_SWITCH_COOLDOWN;
    }
    if (moveRight && this.playerLane < 2) {
      this.playerLane++;
      this.laneSwitchCooldown = LANE_SWITCH_COOLDOWN;
    }
  }

  private updateObstacles(dt: number) {
    for (const o of this.obstacles) {
      if (!o.active) continue;

      o.group.position.z += this.speed * dt;
      o.group.rotation.y += dt * 0.5;

      // Despawn
      if (o.group.position.z > DESPAWN_Z) {
        this.deactivateObstacle(o);
        continue;
      }

      // Collision check
      if (this.invincibilityTimer <= 0) {
        const dx = Math.abs(o.group.position.x - this.playerX);
        const dz = Math.abs(o.group.position.z - this.playerMesh.position.z);
        if (dx < 0.8 && dz < 0.6) {
          this.onHit();
        }
      }
    }
  }

  private updateCollectibles(dt: number, time: number) {
    for (const c of this.collectibles) {
      if (!c.active) continue;

      c.mesh.position.z += this.speed * dt;
      c.mesh.rotation.y += dt * 3;
      c.mesh.position.y = 1 + Math.sin(time * 4 + c.pulsePhase) * 0.15;

      // Pulse scale
      const pulse = 1 + Math.sin(time * 5 + c.pulsePhase) * 0.1;
      c.mesh.scale.setScalar(pulse);

      // Despawn
      if (c.mesh.position.z > DESPAWN_Z) {
        this.deactivateCollectible(c);
        this.currentCombo = 0;
        continue;
      }

      // Collection check
      const dx = Math.abs(c.mesh.position.x - this.playerX);
      const dz = Math.abs(c.mesh.position.z - this.playerMesh.position.z);
      if (dx < 1 && dz < 1) {
        this.collectOrb(c);
      }
    }
  }

  private collectOrb(c: CollectibleObj) {
    this.score += c.value * this.multiplier;
    this.orbsCollected++;
    this.totalOrbsThisRun++;
    this.currentCombo++;
    this.longestCombo = Math.max(this.longestCombo, this.currentCombo);
    this.multiplierTimer = 0;

    // Increase multiplier every 3 orbs
    if (this.currentCombo % 3 === 0 && this.multiplier < MAX_MULTIPLIER) {
      this.multiplier++;
    }

    this.deactivateCollectible(c);
  }

  private onHit() {
    this.lives--;
    this.multiplier = 1;
    this.currentCombo = 0;
    this.invincibilityTimer = INVINCIBILITY_TIME;

    if (this.lives <= 0) {
      this.endGame();
    }
  }

  private endGame() {
    this.state = GameState.GAME_OVER;

    // Check/save high score
    const key = this.mode;
    const prev = this.highScores[key] || 0;
    if (this.score > prev) {
      this.highScores[key] = Math.floor(this.score);
      this.isNewRecord = true;
      this.saveHighScores();
    }

    this.hidePlayerVisual();
    for (const line of this.speedLines) line.visible = false;
  }
}

import {
  createSystem,
  PanelUI,
  PanelDocument,
  UIKitDocument,
  UIKit,
  eq,
  Entity,
} from '@iwsdk/core';

import { GameSystem, GameState, GameMode, GAME_MODES } from './game-system.js';

// ── Helper ────────────────────────────────────────────────────

const getDoc = (e: Entity) =>
  e.getValue(PanelDocument, 'document') as UIKitDocument | undefined;

const setText = (doc: UIKitDocument | undefined, id: string, text: string) =>
  (doc?.getElementById(id) as UIKit.Text | undefined)?.setProperties({ text });

const setVisible = (doc: UIKitDocument | undefined, id: string, visible: boolean) =>
  (doc?.getElementById(id) as UIKit.Text | undefined)?.setProperties({
    display: visible ? ('flex' as any) : ('none' as any),
  });

// ── UISystem ─────────────────────────────────────────────────

export class UISystem extends createSystem({
  menu: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/main-menu.json')],
  },
  hud: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/hud.json')],
  },
  gameOver: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/game-over.json')],
  },
  pause: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/pause-menu.json')],
  },
  modeSelect: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/mode-select.json')],
  },
  settings: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/settings.json')],
  },
  achievements: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/achievements.json')],
  },
  tutorial: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/tutorial.json')],
  },
  countdown: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/countdown.json')],
  },
  newRecord: {
    required: [PanelUI, PanelDocument],
    where: [eq(PanelUI, 'config', './ui/new-record.json')],
  },
}) {
  private gameSystem!: GameSystem;
  private prevState: GameState | null = null;
  private achievementToast = '';
  private achievementToastTimer = 0;
  private lastHudUpdate = 0;

  /** Hide/show an entity based on current game state */
  private syncVisibility(entity: Entity, shouldShow: boolean) {
    if (entity?.object3D) entity.object3D.visible = shouldShow;
  }

  // Panel entities (set on qualify)
  private menuEntity: Entity | null = null;
  private hudEntity: Entity | null = null;
  private gameOverEntity: Entity | null = null;
  private pauseEntity: Entity | null = null;
  private modeSelectEntity: Entity | null = null;
  private settingsEntity: Entity | null = null;
  private achievementsEntity: Entity | null = null;
  private tutorialEntity: Entity | null = null;
  private countdownEntity: Entity | null = null;
  private newRecordEntity: Entity | null = null;

  setRefs(refs: { gameSystem: GameSystem }) {
    this.gameSystem = refs.gameSystem;
  }

  init() {
    // Main menu
    this.queries.menu.subscribe('qualify', (entity) => {
      this.menuEntity = entity;
      this.syncVisibility(entity, this.gameSystem.state === GameState.MENU);
      const doc = getDoc(entity);
      if (!doc) return;

      const playBtn = doc.getElementById('btn-play') as UIKit.Text | undefined;
      playBtn?.addEventListener('click', () => this.gameSystem.startGame(GameMode.CLASSIC));

      const modesBtn = doc.getElementById('btn-modes') as UIKit.Text | undefined;
      modesBtn?.addEventListener('click', () => this.gameSystem.showModeSelect());

      const settingsBtn = doc.getElementById('btn-settings') as UIKit.Text | undefined;
      settingsBtn?.addEventListener('click', () => this.gameSystem.showSettings());

      const achievementsBtn = doc.getElementById('btn-achievements') as UIKit.Text | undefined;
      achievementsBtn?.addEventListener('click', () => this.gameSystem.showAchievements());

      const tutorialBtn = doc.getElementById('btn-tutorial') as UIKit.Text | undefined;
      tutorialBtn?.addEventListener('click', () => this.gameSystem.showTutorial());
    });

    // HUD
    this.queries.hud.subscribe('qualify', (entity) => {
      this.hudEntity = entity;
      this.syncVisibility(entity, false);
    });

    // Game Over
    this.queries.gameOver.subscribe('qualify', (entity) => {
      this.gameOverEntity = entity;
      this.syncVisibility(entity, false);
      const doc = getDoc(entity);
      if (!doc) return;

      const retryBtn = doc.getElementById('btn-retry') as UIKit.Text | undefined;
      retryBtn?.addEventListener('click', () => this.gameSystem.startGame(this.gameSystem.mode));

      const menuBtn = doc.getElementById('btn-menu') as UIKit.Text | undefined;
      menuBtn?.addEventListener('click', () => this.gameSystem.quitToMenu());
    });

    // Pause Menu
    this.queries.pause.subscribe('qualify', (entity) => {
      this.pauseEntity = entity;
      this.syncVisibility(entity, false);
      const doc = getDoc(entity);
      if (!doc) return;

      const resumeBtn = doc.getElementById('btn-resume') as UIKit.Text | undefined;
      resumeBtn?.addEventListener('click', () => this.gameSystem.resumeGame());

      const quitBtn = doc.getElementById('btn-quit') as UIKit.Text | undefined;
      quitBtn?.addEventListener('click', () => this.gameSystem.quitToMenu());
    });

    // Mode Select
    this.queries.modeSelect.subscribe('qualify', (entity) => {
      this.modeSelectEntity = entity;
      this.syncVisibility(entity, false);
      const doc = getDoc(entity);
      if (!doc) return;

      const modes = [GameMode.CLASSIC, GameMode.SPRINT, GameMode.TIME_ATTACK, GameMode.ZEN, GameMode.ENDLESS, GameMode.CHALLENGE];
      for (const mode of modes) {
        const btn = doc.getElementById(`btn-${mode}`) as UIKit.Text | undefined;
        btn?.addEventListener('click', () => this.gameSystem.startGame(mode));
      }

      const backBtn = doc.getElementById('btn-back') as UIKit.Text | undefined;
      backBtn?.addEventListener('click', () => this.gameSystem.showMenu());
    });

    // Settings
    this.queries.settings.subscribe('qualify', (entity) => {
      this.settingsEntity = entity;
      this.syncVisibility(entity, false);
      const doc = getDoc(entity);
      if (!doc) return;

      const backBtn = doc.getElementById('btn-back') as UIKit.Text | undefined;
      backBtn?.addEventListener('click', () => this.gameSystem.showMenu());
    });

    // Achievements
    this.queries.achievements.subscribe('qualify', (entity) => {
      this.achievementsEntity = entity;
      this.syncVisibility(entity, false);
      const doc = getDoc(entity);
      if (!doc) return;

      const backBtn = doc.getElementById('btn-back') as UIKit.Text | undefined;
      backBtn?.addEventListener('click', () => this.gameSystem.showMenu());
    });

    // Tutorial
    this.queries.tutorial.subscribe('qualify', (entity) => {
      this.tutorialEntity = entity;
      this.syncVisibility(entity, false);
      const doc = getDoc(entity);
      if (!doc) return;

      const backBtn = doc.getElementById('btn-back') as UIKit.Text | undefined;
      backBtn?.addEventListener('click', () => this.gameSystem.showMenu());

      const playBtn = doc.getElementById('btn-play') as UIKit.Text | undefined;
      playBtn?.addEventListener('click', () => this.gameSystem.startGame(GameMode.CLASSIC));
    });

    // Countdown
    this.queries.countdown.subscribe('qualify', (entity) => {
      this.countdownEntity = entity;
      this.syncVisibility(entity, false);
    });

    // New Record
    this.queries.newRecord.subscribe('qualify', (entity) => {
      this.newRecordEntity = entity;
      this.syncVisibility(entity, false);
    });
  }

  showAchievementToast(name: string) {
    this.achievementToast = name;
    this.achievementToastTimer = 3;
  }

  update(delta: number, _time: number) {
    const dt = Math.min(delta, 0.1);
    const state = this.gameSystem.state;

    // State changed - update visibility
    if (state !== this.prevState) {
      this.updatePanelVisibility(state);
      this.prevState = state;

      // Update content on state enter
      if (state === GameState.GAME_OVER) this.updateGameOverPanel();
      if (state === GameState.ACHIEVEMENTS) this.updateAchievementsPanel();
    }

    // Continuous updates
    if (state === GameState.PLAYING) {
      this.lastHudUpdate += dt;
      if (this.lastHudUpdate > 0.1) {
        this.updateHUD();
        this.lastHudUpdate = 0;
      }
    }

    if (state === GameState.COUNTDOWN) {
      this.updateCountdownPanel();
    }

    // Achievement toast
    if (this.achievementToastTimer > 0) {
      this.achievementToastTimer -= dt;
      if (this.hudEntity) {
        const doc = getDoc(this.hudEntity);
        setText(doc, 'achievement-toast', `Unlocked: ${this.achievementToast}`);
        setVisible(doc, 'achievement-toast', true);
      }
    } else if (this.hudEntity) {
      const doc = getDoc(this.hudEntity);
      setVisible(doc, 'achievement-toast', false);
    }
  }

  private updatePanelVisibility(state: GameState) {
    const show = (entity: Entity | null, visible: boolean) => {
      if (entity?.object3D) entity.object3D.visible = visible;
    };

    show(this.menuEntity, state === GameState.MENU);
    show(this.hudEntity, state === GameState.PLAYING || state === GameState.COUNTDOWN);
    show(this.gameOverEntity, state === GameState.GAME_OVER);
    show(this.pauseEntity, state === GameState.PAUSED);
    show(this.modeSelectEntity, state === GameState.MODE_SELECT);
    show(this.settingsEntity, state === GameState.SETTINGS);
    show(this.achievementsEntity, state === GameState.ACHIEVEMENTS);
    show(this.tutorialEntity, state === GameState.TUTORIAL);
    show(this.countdownEntity, state === GameState.COUNTDOWN);
    show(this.newRecordEntity, state === GameState.GAME_OVER && this.gameSystem.isNewRecord);
  }

  private updateHUD() {
    if (!this.hudEntity) return;
    const doc = getDoc(this.hudEntity);
    if (!doc) return;

    const gs = this.gameSystem;
    setText(doc, 'score', `Score: ${Math.floor(gs.score).toLocaleString()}`);
    setText(doc, 'distance', `${Math.floor(gs.distance)}m`);
    setText(doc, 'speed', `${gs.speed.toFixed(1)} m/s`);
    setText(doc, 'multiplier', gs.multiplier > 1 ? `x${gs.multiplier}` : '');
    setText(doc, 'orbs', `Orbs: ${gs.orbsCollected}`);

    // Lives display
    const livesText = gs.lives > 5 ? `${gs.lives}` : '*'.repeat(gs.lives);
    setText(doc, 'lives', livesText);

    // Timer (for timed modes)
    const cfg = gs.modeConfig;
    if (cfg.timeLimit > 0) {
      const remaining = Math.max(0, cfg.timeLimit - gs.elapsedTime);
      const mins = Math.floor(remaining / 60);
      const secs = Math.floor(remaining % 60);
      setText(doc, 'timer', `${mins}:${secs.toString().padStart(2, '0')}`);
      setVisible(doc, 'timer', true);
    } else {
      setVisible(doc, 'timer', false);
    }

    // Sprint progress
    if (cfg.targetDistance > 0) {
      const pct = Math.min(100, (gs.distance / cfg.targetDistance) * 100);
      setText(doc, 'progress', `${pct.toFixed(0)}%`);
      setVisible(doc, 'progress', true);
    } else {
      setVisible(doc, 'progress', false);
    }
  }

  private updateCountdownPanel() {
    if (!this.countdownEntity) return;
    const doc = getDoc(this.countdownEntity);
    if (!doc) return;

    const val = this.gameSystem.countdownValue;
    setText(doc, 'countdown-text', val > 0 ? `${val}` : 'GO!');
  }

  private updateGameOverPanel() {
    if (!this.gameOverEntity) return;
    const doc = getDoc(this.gameOverEntity);
    if (!doc) return;

    const gs = this.gameSystem;
    setText(doc, 'final-score', `${Math.floor(gs.score).toLocaleString()}`);
    setText(doc, 'final-distance', `${Math.floor(gs.distance)}m`);
    setText(doc, 'final-orbs', `${gs.orbsCollected}`);
    setText(doc, 'final-time', `${Math.floor(gs.elapsedTime)}s`);
    setText(doc, 'final-speed', `${gs.maxSpeed.toFixed(1)} m/s`);
    setText(doc, 'final-combo', `${gs.longestCombo}`);
    setText(doc, 'high-score', `Best: ${(gs.highScores[gs.mode] || 0).toLocaleString()}`);
    setText(doc, 'mode-name', GAME_MODES[gs.mode].name);

    if (gs.isNewRecord) {
      setVisible(doc, 'new-record-badge', true);
    } else {
      setVisible(doc, 'new-record-badge', false);
    }
  }

  private updateAchievementsPanel() {
    if (!this.achievementsEntity) return;
    const doc = getDoc(this.achievementsEntity);
    if (!doc) return;

    const gs = this.gameSystem;
    const unlocked = gs.getAchievementCount();
    const total = gs.achievements.length;
    setText(doc, 'ach-count', `${unlocked} / ${total}`);

    // Update achievement list (first 12 shown)
    for (let i = 0; i < 12; i++) {
      const a = gs.achievements[i];
      if (a) {
        setText(doc, `ach-name-${i}`, a.name);
        setText(doc, `ach-desc-${i}`, a.description);
        setText(doc, `ach-status-${i}`, a.unlocked ? '[DONE]' : '[ ]');
      }
    }
  }
}

import {
  World,
  Mesh,
  Group,
  BoxGeometry,
  PlaneGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  Color,
  AmbientLight,
  PointLight,
  DirectionalLight,
  Fog,
  DoubleSide,
  LineSegments,
  LineBasicMaterial,
  BufferGeometry,
  Float32BufferAttribute,
  PanelUI,
  Follower,
} from '@iwsdk/core';

import { GameSystem } from './game-system.js';
import { UISystem } from './ui-system.js';

async function main() {
  const container = document.getElementById('app') as HTMLDivElement;

  const world = await World.create(container, {
    xr: { offer: 'once' as const },
    render: {
      fov: 75,
      near: 0.1,
      far: 200,
      defaultLighting: false,
    },
    features: {
      locomotion: false,
      grabbing: false,
      physics: false,
    },
  });

  // Set initial camera position
  world.camera.position.set(0, 1.6, 0);
  world.camera.lookAt(0, 1.5, -10);

  // Scene atmosphere
  world.scene.background = new Color(0x000811);
  world.scene.fog = new Fog(0x000811, 30, 100);

  // Lighting
  const ambient = new AmbientLight(0x112244, 0.3);
  world.scene.add(ambient);

  const dirLight = new DirectionalLight(0x4488ff, 0.4);
  dirLight.position.set(0, 10, -5);
  world.scene.add(dirLight);

  for (let i = 0; i < 6; i++) {
    const pl = new PointLight(0x00ffff, 1.5, 30);
    pl.position.set(i % 2 === 0 ? -4 : 4, 3, -i * 15);
    world.scene.add(pl);
  }

  buildCorridor(world);

  world.registerSystem(GameSystem);
  world.registerSystem(UISystem);

  const gameSystem = world.getSystem(GameSystem)!;
  const uiSystem = world.getSystem(UISystem)!;

  const cam = world.camera;

  const panelConfigs: Array<{ config: string; offset: [number, number, number]; spd: number }> = [
    { config: './ui/main-menu.json', offset: [0, 0, -2.5], spd: 6 },
    { config: './ui/hud.json', offset: [0, -0.7, -2], spd: 8 },
